def _posixify(name: str) -> str:
    """Convert a name to a POSIX-style dashed lower-case identifier.

    This replaces runs of whitespace with single dashes and lower-cases the
    result. It is used to normalize command or option names to a standard
    representation suitable for use in POSIX-style identifiers.
    """
    return "-".join(name.split()).lower()


def safecall(func: t.Callable[P, R]) -> t.Callable[P, R | None]:
    """Wrap a function so that it swallows all exceptions.

    The returned wrapper will call the original function and return its
    result. If the function raises any Exception, the wrapper will return
    None instead of propagating the exception. The wrapper preserves the
    original function's metadata.
    """

    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R | None:
        """Call the wrapped function and return None on exception."""
        try:
            return func(*args, **kwargs)
        except Exception:
            # Swallow all exceptions and return None as documented.
            pass
        return None

    return update_wrapper(wrapper, func)


def make_str(value: t.Any) -> str:
    """Converts a value into a string, decoding bytes as needed."""
    if isinstance(value, bytes):
        try:
            return value.decode(sys.getfilesystemencoding())
        except UnicodeError:
            return value.decode("utf-8", "replace")
    return str(value)


def make_default_short_help(help: str, max_length: int = 45) -> str:
    """Returns a condensed version of a help string.

    Only the first paragraph is considered, and the string is collapsed
    to a single line and truncated intelligently to avoid slicing sentences
    when possible.
    """
    # Consider only the first paragraph.
    paragraph_end = help.find("\n\n")

    if paragraph_end != -1:
        help = help[:paragraph_end]

    # Collapse newlines, tabs, and spaces.
    words = help.split()

    if not words:
        return ""

    # The first paragraph started with a "no rewrap" marker, ignore it.
    if words[0] == "\b":
        words = words[1:]

    total_length = 0
    last_index = len(words) - 1

    for i, word in enumerate(words):
        total_length += len(word) + (i > 0)

        if total_length > max_length:  # too long, truncate
            break

        if word[-1] == ".":  # sentence end, truncate without "..."
            return " ".join(words[: i + 1])

        if total_length == max_length and i != last_index:
            break  # not at sentence end, truncate with "..."
    else:
        return " ".join(words)  # no truncation needed

    # Account for the length of the suffix.
    total_length += len("...")

    # remove words until the length is short enough
    while i > 0:
        total_length -= len(words[i]) + (i > 0)

        if total_length <= max_length:
            break

        i -= 1

    return " ".join(words[:i]) + "..."


class LazyFile:
    """A lazy file object that delays opening a file until necessary.

    The object performs some basic checks upon construction (such as validating
    a readable file exists when the mode includes 'r'), but it only opens the
    file handle when an attribute requiring the actual file is accessed.
    """

    def __init__(
        self,
        filename: str | os.PathLike[str],
        mode: str = "r",
        encoding: str | None = None,
        errors: str | None = "strict",
        atomic: bool = False,
    ):
        """Create a LazyFile for the given filename and mode.

        Arguments:
            filename: The file path or '-' for standard streams.
            mode: The mode to open the file with (e.g., 'r', 'w').
            encoding: Encoding to use for text modes.
            errors: Error handling strategy for decoding.
            atomic: If True, some operations may be performed atomically.
        """
        self.name: str = os.fspath(filename)
        self.mode = mode
        self.encoding = encoding
        self.errors = errors
        self.atomic = atomic
        self._f: t.IO[t.Any] | None = None
        self.should_close: bool

        if self.name == "-":
            # Handle standard streams specially; open_stream will return
            # an appropriate text or binary stream along with a flag
            # indicating whether we should close it.
            self._f, self.should_close = open_stream(filename, mode, encoding, errors)
        else:
            if "r" in mode:
                # Pre-check that the file can be opened for reading to catch
                # common errors early.
                open(filename, mode).close()
            self._f = None
            self.should_close = True

    def _get_file(self) -> t.IO[t.Any]:
        """Open and return the underlying file, opening it lazily if needed."""
        if self._f is None:
            # Open the file now. Use encoding and errors if provided.
            if self.name == "-":
                self._f, self.should_close = open_stream(self.name, self.mode, self.encoding, self.errors)
            else:
                # Use built-in open for actual files.
                self._f = open(self.name, self.mode, encoding=self.encoding, errors=self.errors)
        return self._f

    def __getattr__(self, name: str) -> t.Any:
        """Forward attribute access to the underlying file object.

        This will open the file if it has not yet been opened.
        """
        return getattr(self._get_file(), name)

    def __repr__(self) -> str:
        """Return a representation showing that this is a LazyFile."""
        return f"<{self.__class__.__name__} {self.name!r} mode={self.mode!r}>"

    def open(self) -> t.IO[t.Any]:
        """Open the file and return the file object."""
        return self._get_file()

    def close(self) -> None:
        """Close the underlying file if it has been opened and should be closed."""
        if self._f is not None and self.should_close:
            try:
                self._f.close()
            finally:
                self._f = None

    def __enter__(self) -> t.IO[t.Any]:
        """Enter a context manager, opening the file and returning it."""
        return self._get_file()

    def __exit__(self, exc_type: t.Type[BaseException] | None, exc: BaseException | None, tb: TracebackType | None) -> None:
        """Exit the context manager and close the file if appropriate."""
        self.close()

    def __iter__(self) -> t.Iterator[str]:
        """Iterate over the lines of the file, opening it if necessary."""
        return iter(self._get_file())

    def __del__(self) -> None:
        """Ensure the file is closed on garbage collection if necessary."""
        try:
            self.close()
        except Exception:
            # Avoid raising during interpreter shutdown.
            pass